const handleStartMatch = async () => {
  console.log('[TeamDashboard] Start Match pressed');

  if (!dashboard?.upcomingFixtures || dashboard.upcomingFixtures.length === 0) {
    Alert.alert(
      'No Upcoming Fixtures',
      'Create a fixture first.',
      [
        { text: 'Cancel', style: 'cancel' },
        { 
          text: 'Create Fixture', 
          onPress: () => router.push(`/create-fixture/${teamId}`)
        }
      ]
    );
    return;
  }

  const selectFixture = async (fixture: Fixture) => {
    try {
      // Check if lineup exists
      const response = await authenticatedGet(`/api/lineups?fixtureId=${fixture.id}`);

      if (!response || response.length === 0) {
        Alert.alert(
          'No Lineup',
          'Build your team first before starting the match.',
          [
            { text: 'Cancel', style: 'cancel' },
            { 
              text: 'Build Team', 
              onPress: () => router.push(`/lineups/${fixture.id}`)
            }
          ]
        );
        return;
      }

      router.push(`/match-tracker-live/${fixture.id}`);
    } catch (error) {
      console.error('[TeamDashboard] Failed to check lineup:', error);
      Alert.alert('Error', 'Could not verify lineup status');
    }
  };

  if (dashboard.upcomingFixtures.length === 1) {
    await selectFixture(dashboard.upcomingFixtures[0]);
  } else {
    setShowFixturePicker(true);
    setFixturePickerMode('match');
  }
};
