const safeConsoleLog = (...args: any[]) => {
  try {
    // Standard console.log first
    if (typeof console !== "undefined" && typeof console.log === "function") {
      console.log(...args);
      return;
    }
  } catch {}

  try {
    // Browser fallback (avoid proto tricks)
    if (
      typeof window !== "undefined" &&
      (window as any).console &&
      typeof (window as any).console.log === "function"
    ) {
      (window as any).console.log(...args);
      return;
    }
  } catch {}

  // Last resort: do nothing
};

